document.addEventListener("DOMContentLoaded",()=>{document.getElementById("sfragida").addEventListener("change",function(e){var t=document.getElementById("preview-image"),n=e.target.files[0];if(n){var a=new FileReader;a.onload=function(e){t.src=e.target.result,t.style.display="inline-block"},a.readAsDataURL(n)}})});